#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e5+10,M=2e5+10;
struct Graph
{
	int head[N],des[M],nxt[M],cnt;
	inline void ins(int x,int y){nxt[++cnt]=head[x];head[x]=cnt;des[cnt]=y;}
}a;
int top[N],fa[N],dep[N],mxs[N],siz[N],n,m,ans[N];
struct Seg{int l,r,mx,res;}t[N*50];int Rt[N],cnt;
inline void update(int k)
{
	if(t[t[k].l].mx>=t[t[k].r].mx)t[k].mx=t[t[k].l].mx,t[k].res=t[t[k].l].res;
	else t[k].mx=t[t[k].r].mx,t[k].res=t[t[k].r].res;
}
inline void add(int &cur,int pos,int val,int l=1,int r=N-10)
{
	if(!cur)cur=++cnt;if(l==r){t[cur].mx+=val;t[cur].res=t[cur].mx?l:0;return;}
	int mid=(l+r)>>1;pos<=mid?add(t[cur].l,pos,val,l,mid):add(t[cur].r,pos,val,mid+1,r);update(cur);
}
inline int merge(int x,int y,int l=1,int r=N-10)
{
	if(!x||!y)return x|y;if(l==r){t[x].mx+=t[y].mx;t[x].res=t[x].mx?l:0;return x;}int mid=(l+r)>>1;
	t[x].l=merge(t[x].l,t[y].l,l,mid);t[x].r=merge(t[x].r,t[y].r,mid+1,r);update(x);return x;
}
inline void dfs1(int u=1,int f=0)
{
	dep[u]=dep[f]+1;siz[u]=1;fa[u]=f;
	int mx=0;grep(a,u,i)
	{
		int v=a.des[i];if(v==f)continue;dfs1(v,u);
		siz[u]+=siz[v];siz[v]>mx?(mx=siz[v],mxs[u]=v):0;
	}
}
inline void dfs2(int u=1,int f=0,int tp=1)
{
	top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
	grep(a,u,i){int v=a.des[i];if(v^f&&v^mxs[u])dfs2(v,u,v);}
}
inline int lca(int u,int v)
{
	while(top[u]^top[v])
	{
		if(dep[top[u]]<dep[top[v]])swap(u,v);
		u=fa[top[u]];
	}
	return dep[u]<dep[v]?u:v;
}
inline void dfs3(int u=1,int f=0)
{
	grep(a,u,i)
	{
		int v=a.des[i];if(v==f)continue;
		dfs3(v,u);Rt[u]=merge(Rt[u],Rt[v]);
	}
	ans[u]=t[Rt[u]].res;
}
int main()
{
	int n=read(),m=read();rep(2,n,i){int x=read(),y=read();a.ins(x,y);a.ins(y,x);}
	dfs1();dfs2();//while(1){printf("%d\n",lca(read(),read()));}
	rep(1,m,i)
	{
		int x=read(),y=read(),z=read();
		int Lca=lca(x,y);add(Rt[x],z,1);add(Rt[y],z,1);add(Rt[Lca],z,-1);
		if(fa[Lca])add(Rt[fa[Lca]],z,-1);
	}
	dfs3();rep(1,n,i)printf("%d\n",ans[i]);
}
